class MyComponent(Component):
    setup() {
        this.state = useState({count: 0})
    }

    increment() {
        this.state.count += 1
    }

    static template = xml`<div>
        <button t-on-click="this.increment">Increment</button>
        <span><t t-esc="this.state.count"/></span>
    </div>`
